import { ark } from '@ark-ui/react/factory';
import {
  Listbox as ListboxPrimitive,
  type CollectionItem,
  type ListboxRootComponent,
  type ListboxRootProps,
  type ListboxRootProviderComponent,
  type ListboxRootProviderProps,
  useListbox,
  useListboxContext,
  useListboxItemContext,
} from '@ark-ui/react/listbox';
import { clsx } from 'clsx';
import type { ComponentProps, ComponentRef, ForwardedRef } from 'react';
import { forwardRef } from 'react';
import { CheckIcon, SearchIcon } from '@/lib/moduix/icons/ui';
import { normalizeClassName } from '@/lib/moduix/normalizeClassName';
import { CloseButton } from '../close-button';
import styles from './Listbox.module.css';

const ListboxRoot = forwardRef(function ListboxRoot<T extends CollectionItem>(
  { className, ...props }: ListboxRootProps<T>,
  ref: ForwardedRef<HTMLDivElement>,
) {
  return (
    <ListboxPrimitive.Root
      ref={ref}
      data-slot="listbox-root"
      className={clsx(styles.root, normalizeClassName(className))}
      {...props}
    />
  );
}) as ListboxRootComponent;

const ListboxRootProvider = forwardRef(function ListboxRootProvider<T extends CollectionItem>(
  { className, ...props }: ListboxRootProviderProps<T>,
  ref: ForwardedRef<HTMLDivElement>,
) {
  return (
    <ListboxPrimitive.RootProvider
      ref={ref}
      data-slot="listbox-root-provider"
      className={clsx(styles.root, normalizeClassName(className))}
      {...props}
    />
  );
}) as ListboxRootProviderComponent;

const ListboxLabel = forwardRef<
  ComponentRef<typeof ListboxPrimitive.Label>,
  ComponentProps<typeof ListboxPrimitive.Label>
>(function ListboxLabel({ className, ...props }, ref) {
  return (
    <ListboxPrimitive.Label
      ref={ref}
      data-slot="listbox-label"
      className={clsx(styles.label, normalizeClassName(className))}
      {...props}
    />
  );
});

const ListboxInput = forwardRef<
  ComponentRef<typeof ListboxPrimitive.Input>,
  ComponentProps<typeof ListboxPrimitive.Input>
>(function ListboxInput({ className, ...props }, ref) {
  return (
    <ListboxPrimitive.Input
      ref={ref}
      data-slot="listbox-input"
      className={clsx(styles.input, normalizeClassName(className))}
      {...props}
    />
  );
});

function ListboxFilter({ className, children, ...props }: ComponentProps<'div'>) {
  return (
    <div
      data-slot="listbox-filter"
      className={clsx(styles.filter, normalizeClassName(className))}
      {...props}
    >
      <SearchIcon data-slot="listbox-filter-icon" className={styles.filterIcon} />
      {children}
    </div>
  );
}

const ListboxClearTrigger = forwardRef<HTMLButtonElement, ComponentProps<'button'>>(
  function ListboxClearTrigger(
    { 'aria-label': ariaLabel = 'Clear search', className, children, type = 'button', ...props },
    ref,
  ) {
    return (
      <ark.button
        ref={ref}
        asChild
        data-slot="listbox-clear-trigger"
        type={type}
        aria-label={ariaLabel}
        className={clsx(styles.clearTrigger, normalizeClassName(className))}
        {...props}
      >
        <CloseButton.Root aria-label={ariaLabel} type={type}>
          {children}
        </CloseButton.Root>
      </ark.button>
    );
  },
);

const ListboxContent = forwardRef<
  ComponentRef<typeof ListboxPrimitive.Content>,
  ComponentProps<typeof ListboxPrimitive.Content>
>(function ListboxContent({ className, ...props }, ref) {
  return (
    <ListboxPrimitive.Content
      ref={ref}
      data-slot="listbox-content"
      className={clsx(styles.content, normalizeClassName(className))}
      {...props}
    />
  );
});

const ListboxEmpty = forwardRef<
  ComponentRef<typeof ListboxPrimitive.Empty>,
  ComponentProps<typeof ListboxPrimitive.Empty>
>(function ListboxEmpty({ className, ...props }, ref) {
  return (
    <ListboxPrimitive.Empty
      ref={ref}
      data-slot="listbox-empty"
      className={clsx(styles.empty, normalizeClassName(className))}
      {...props}
    />
  );
});

const ListboxItemGroup = forwardRef<
  ComponentRef<typeof ListboxPrimitive.ItemGroup>,
  ComponentProps<typeof ListboxPrimitive.ItemGroup>
>(function ListboxItemGroup({ className, ...props }, ref) {
  return (
    <ListboxPrimitive.ItemGroup
      ref={ref}
      data-slot="listbox-item-group"
      className={clsx(styles.itemGroup, normalizeClassName(className))}
      {...props}
    />
  );
});

const ListboxItemGroupLabel = forwardRef<
  ComponentRef<typeof ListboxPrimitive.ItemGroupLabel>,
  ComponentProps<typeof ListboxPrimitive.ItemGroupLabel>
>(function ListboxItemGroupLabel({ className, ...props }, ref) {
  return (
    <ListboxPrimitive.ItemGroupLabel
      ref={ref}
      data-slot="listbox-item-group-label"
      className={clsx(styles.itemGroupLabel, normalizeClassName(className))}
      {...props}
    />
  );
});

const ListboxItem = forwardRef<
  ComponentRef<typeof ListboxPrimitive.Item>,
  ComponentProps<typeof ListboxPrimitive.Item>
>(function ListboxItem({ className, ...props }, ref) {
  return (
    <ListboxPrimitive.Item
      ref={ref}
      data-slot="listbox-item"
      className={clsx(styles.item, normalizeClassName(className))}
      {...props}
    />
  );
});

const ListboxItemText = forwardRef<
  ComponentRef<typeof ListboxPrimitive.ItemText>,
  ComponentProps<typeof ListboxPrimitive.ItemText>
>(function ListboxItemText({ className, ...props }, ref) {
  return (
    <ListboxPrimitive.ItemText
      ref={ref}
      data-slot="listbox-item-text"
      className={clsx(styles.itemText, normalizeClassName(className))}
      {...props}
    />
  );
});

const ListboxItemIndicator = forwardRef<
  ComponentRef<typeof ListboxPrimitive.ItemIndicator>,
  ComponentProps<typeof ListboxPrimitive.ItemIndicator>
>(function ListboxItemIndicator({ className, children, ...props }, ref) {
  return (
    <ListboxPrimitive.ItemIndicator
      ref={ref}
      data-slot="listbox-item-indicator"
      className={clsx(styles.itemIndicator, normalizeClassName(className))}
      {...props}
    >
      {children ?? <CheckIcon />}
    </ListboxPrimitive.ItemIndicator>
  );
});

const ListboxValueText = forwardRef<
  ComponentRef<typeof ListboxPrimitive.ValueText>,
  ComponentProps<typeof ListboxPrimitive.ValueText>
>(function ListboxValueText({ className, ...props }, ref) {
  return (
    <ListboxPrimitive.ValueText
      ref={ref}
      data-slot="listbox-value-text"
      className={clsx(styles.valueText, normalizeClassName(className))}
      {...props}
    />
  );
});

function ListboxItemTextContent({ className, ...props }: ComponentProps<'span'>) {
  return (
    <span
      data-slot="listbox-item-text-content"
      className={clsx(styles.itemTextContent, normalizeClassName(className))}
      {...props}
    />
  );
}

function ListboxItemTextIcon({ className, ...props }: ComponentProps<'span'>) {
  return (
    <span
      data-slot="listbox-item-text-icon"
      className={clsx(styles.itemTextIcon, normalizeClassName(className))}
      {...props}
    />
  );
}

function ListboxItemTextLabel({ className, ...props }: ComponentProps<'span'>) {
  return (
    <span
      data-slot="listbox-item-text-label"
      className={clsx(styles.itemTextLabel, normalizeClassName(className))}
      {...props}
    />
  );
}

const Listbox = Object.assign(ListboxRoot, {
  Root: ListboxRoot,
  RootProvider: ListboxRootProvider,
  Label: ListboxLabel,
  Input: ListboxInput,
  Filter: ListboxFilter,
  ClearTrigger: ListboxClearTrigger,
  Content: ListboxContent,
  Empty: ListboxEmpty,
  ItemGroup: ListboxItemGroup,
  ItemGroupLabel: ListboxItemGroupLabel,
  Item: ListboxItem,
  ItemText: ListboxItemText,
  ItemIndicator: ListboxItemIndicator,
  ValueText: ListboxValueText,
  Context: ListboxPrimitive.Context,
  ItemContext: ListboxPrimitive.ItemContext,
  ItemTextContent: ListboxItemTextContent,
  ItemTextIcon: ListboxItemTextIcon,
  ItemTextLabel: ListboxItemTextLabel,
  useListbox,
  useListboxContext,
  useListboxItemContext,
});

export { Listbox, useListbox, useListboxContext, useListboxItemContext };

@layer moduix.components {
  .root {
    box-sizing: border-box;
    display: flex;
    width: var(--moduix-listbox-width, 16rem);
    max-width: var(--moduix-listbox-max-width, 100%);
    min-width: 0;
    flex-direction: column;
    gap: var(--moduix-listbox-root-gap, var(--moduix-spacing-3));
    color: var(--moduix-listbox-color, var(--moduix-color-foreground));

    &[data-disabled] {
      opacity: var(--moduix-listbox-disabled-opacity, var(--moduix-opacity-disabled));
    }
  }

  .label {
    color: var(
      --moduix-listbox-label-color,
      var(--moduix-listbox-color, var(--moduix-color-foreground))
    );
    font-size: var(--moduix-listbox-label-font-size, var(--moduix-text-sm));
    font-weight: var(--moduix-listbox-label-font-weight, var(--moduix-weight-medium));
    line-height: var(--moduix-listbox-label-line-height, var(--moduix-line-height-text-sm));
    user-select: none;
  }

  .input {
    box-sizing: border-box;
    width: 100%;
    min-height: var(--moduix-listbox-input-height, var(--moduix-size-md));
    margin: 0;
    border: var(
        --moduix-listbox-input-border-width,
        var(--moduix-listbox-border-width, var(--moduix-border-width-sm))
      )
      solid
      var(
        --moduix-listbox-input-border-color,
        var(--moduix-listbox-border-color, var(--moduix-color-border))
      );
    border-radius: var(
      --moduix-listbox-input-radius,
      var(--moduix-listbox-radius, var(--moduix-radius-md))
    );
    padding: var(--moduix-listbox-input-padding-y, var(--moduix-spacing-1))
      var(--moduix-listbox-input-padding-x, var(--moduix-spacing-3));
    background-color: var(--moduix-listbox-input-bg, var(--moduix-color-background));
    color: var(
      --moduix-listbox-input-color,
      var(--moduix-listbox-color, var(--moduix-color-foreground))
    );
    font: inherit;
    font-size: var(--moduix-listbox-input-font-size, var(--moduix-text-md));
    line-height: var(--moduix-listbox-input-line-height, var(--moduix-line-height-text-md));
    outline: var(
        --moduix-listbox-input-focus-ring-width,
        var(
          --moduix-listbox-focus-ring-width,
          var(--moduix-focus-ring-inset-width, var(--moduix-border-width-sm))
        )
      )
      solid transparent;
    outline-offset: calc(
      var(
          --moduix-listbox-input-focus-ring-width,
          var(
            --moduix-listbox-focus-ring-width,
            var(--moduix-focus-ring-inset-width, var(--moduix-border-width-sm))
          )
        ) *
        -1
    );
    transition:
      border-color var(--moduix-listbox-transition, var(--moduix-transition-default)),
      outline-color var(--moduix-listbox-transition, var(--moduix-transition-default)),
      opacity var(--moduix-listbox-transition, var(--moduix-transition-default));

    &::placeholder {
      color: var(--moduix-listbox-placeholder-color, var(--moduix-color-muted-foreground));
    }

    &:focus-visible {
      outline-color: var(
        --moduix-listbox-input-focus-ring-color,
        var(--moduix-listbox-focus-ring-color, var(--moduix-color-ring))
      );
    }

    &[data-disabled],
    &[disabled] {
      opacity: var(--moduix-listbox-disabled-opacity, var(--moduix-opacity-disabled));
      cursor: default;
    }
  }

  .filter {
    box-sizing: border-box;
    position: relative;
    width: 100%;

    &:has(+ .content) .input {
      border-bottom: 0;
      border-bottom-right-radius: 0;
      border-bottom-left-radius: 0;
    }
  }

  .filter + .content {
    margin-top: calc(-1 * var(--moduix-listbox-root-gap, var(--moduix-spacing-3)));
    border-top-left-radius: 0;
    border-top-right-radius: 0;
  }

  .filterIcon {
    position: absolute;
    z-index: 1;
    top: 50%;
    inset-inline-start: var(--moduix-listbox-filter-padding-x, var(--moduix-spacing-3));
    width: var(--moduix-listbox-filter-icon-size, var(--moduix-spacing-4));
    height: var(--moduix-listbox-filter-icon-size, var(--moduix-spacing-4));
    color: var(--moduix-listbox-filter-icon-color, var(--moduix-color-muted-foreground));
    pointer-events: none;
    transform: translateY(-50%);
  }

  .filter .input {
    min-height: var(
      --moduix-listbox-filter-height,
      var(--moduix-listbox-input-height, var(--moduix-size-md))
    );
    padding-inline-start: calc(
      var(--moduix-listbox-filter-padding-x, var(--moduix-spacing-3)) +
        var(--moduix-listbox-filter-icon-size, var(--moduix-spacing-4)) +
        var(--moduix-listbox-filter-input-padding-x, var(--moduix-spacing-2))
    );
    padding-inline-end: calc(
      var(--moduix-listbox-filter-padding-x, var(--moduix-spacing-3)) +
        var(--moduix-listbox-filter-action-size, var(--moduix-size-xs)) +
        var(--moduix-listbox-filter-input-padding-x, var(--moduix-spacing-2))
    );
    background-color: var(--moduix-listbox-bg, var(--moduix-color-background));

    &:focus-visible {
      outline-color: transparent;
    }
  }

  .clearTrigger {
    position: absolute;
    z-index: 1;
    top: 50%;
    inset-inline-end: var(--moduix-listbox-filter-padding-x, var(--moduix-spacing-3));
    transform: translateY(-50%);
    --moduix-close-button-size: var(--moduix-listbox-filter-action-size, var(--moduix-size-xs));
    --moduix-close-button-radius: var(
      --moduix-listbox-filter-action-radius,
      var(--moduix-radius-sm)
    );
    --moduix-close-button-bg: var(--moduix-listbox-filter-action-bg, transparent);
    --moduix-close-button-bg-hover: var(
      --moduix-listbox-filter-action-bg-hover,
      var(--moduix-color-muted)
    );
    --moduix-close-button-color: var(
      --moduix-listbox-filter-icon-color,
      var(--moduix-color-muted-foreground)
    );
    --moduix-close-button-color-hover: var(
      --moduix-listbox-filter-action-color-hover,
      var(--moduix-color-foreground)
    );
    --moduix-close-button-icon-size: var(
      --moduix-listbox-filter-icon-size,
      var(--moduix-spacing-4)
    );
    --moduix-close-button-transition: var(
      --moduix-listbox-transition,
      var(--moduix-transition-default)
    );
  }

  .content {
    box-sizing: border-box;
    display: flex;
    min-height: 0;
    max-height: var(--moduix-listbox-content-max-height, 14rem);
    flex-direction: column;
    overflow-x: hidden;
    overflow-y: auto;
    border: var(--moduix-listbox-border-width, var(--moduix-border-width-sm)) solid
      var(--moduix-listbox-border-color, var(--moduix-color-border));
    border-radius: var(--moduix-listbox-radius, var(--moduix-radius-md));
    padding-block: var(
      --moduix-listbox-content-padding-y,
      var(--moduix-popup-list-padding-y, var(--moduix-spacing-1))
    );
    background-color: var(--moduix-listbox-bg, var(--moduix-color-background));
    color: var(--moduix-listbox-color, var(--moduix-color-foreground));
    outline: var(
        --moduix-listbox-focus-ring-width,
        var(--moduix-focus-ring-inset-width, var(--moduix-border-width-sm))
      )
      solid transparent;
    outline-offset: calc(
      var(
          --moduix-listbox-focus-ring-width,
          var(--moduix-focus-ring-inset-width, var(--moduix-border-width-sm))
        ) *
        -1
    );
    overscroll-behavior: auto;
    scrollbar-gutter: stable;
    scroll-padding-block: var(
      --moduix-listbox-content-padding-y,
      var(--moduix-popup-list-padding-y, var(--moduix-spacing-1))
    );
    transition:
      border-color var(--moduix-listbox-transition, var(--moduix-transition-default)),
      outline-color var(--moduix-listbox-transition, var(--moduix-transition-default));

    &[data-layout='grid'] {
      display: grid;
      grid-template-columns: repeat(var(--column-count), minmax(0, 1fr));
      gap: var(--moduix-listbox-grid-gap, var(--moduix-spacing-1));
      padding: var(--moduix-listbox-grid-padding, var(--moduix-spacing-2));
    }

    &[data-orientation='horizontal']:not([data-layout='grid']) {
      flex-direction: row;
      gap: var(--moduix-listbox-horizontal-gap, var(--moduix-spacing-2));
      max-height: var(--moduix-listbox-horizontal-content-max-height, none);
      overflow-x: auto;
      overflow-y: hidden;
      padding-inline: var(--moduix-listbox-content-padding-y, var(--moduix-spacing-1));
    }
  }

  .empty {
    padding-block: var(--moduix-listbox-empty-padding-y, var(--moduix-spacing-1));
    padding-inline: var(--moduix-listbox-empty-padding-x, var(--moduix-spacing-3));
    color: var(--moduix-listbox-empty-color, var(--moduix-color-muted-foreground));
    font-size: var(--moduix-listbox-empty-font-size, var(--moduix-text-sm));
    line-height: var(--moduix-listbox-empty-line-height, var(--moduix-line-height-text-sm));
    text-align: center;
  }

  .itemGroup {
    display: flex;
    flex-direction: column;

    & + & {
      margin-top: var(--moduix-listbox-item-group-gap, var(--moduix-spacing-2));
    }
  }

  .itemGroupLabel {
    padding-block: var(
      --moduix-listbox-item-group-label-padding-y,
      var(--moduix-popup-group-label-padding-y, var(--moduix-spacing-1))
    );
    padding-inline: var(--moduix-listbox-item-group-label-padding-x, var(--moduix-spacing-2));
    color: var(
      --moduix-listbox-item-group-label-color,
      var(--moduix-popup-group-label-color, var(--moduix-color-muted-foreground))
    );
    font-size: var(
      --moduix-listbox-item-group-label-font-size,
      var(--moduix-popup-group-label-font-size, var(--moduix-text-xs))
    );
    font-weight: var(
      --moduix-listbox-item-group-label-font-weight,
      var(--moduix-popup-group-label-font-weight, var(--moduix-weight-regular))
    );
    line-height: var(
      --moduix-listbox-item-group-label-line-height,
      var(--moduix-popup-group-label-line-height, var(--moduix-line-height-text-xs))
    );
    user-select: none;
  }

  .item {
    position: relative;
    box-sizing: border-box;
    display: grid;
    width: calc(100% - var(--moduix-listbox-item-inset-x, var(--moduix-spacing-2)));
    min-height: var(
      --moduix-listbox-item-min-height,
      var(--moduix-popup-item-min-height, var(--moduix-size-sm))
    );
    grid-template-columns: minmax(0, 1fr) var(
        --moduix-listbox-item-indicator-size,
        var(--moduix-spacing-4)
      );
    align-items: center;
    gap: var(--moduix-listbox-item-gap, var(--moduix-spacing-2));
    margin-inline: calc(var(--moduix-listbox-item-inset-x, var(--moduix-spacing-2)) / 2);
    border: var(--moduix-listbox-item-border-width, 0) solid
      var(--moduix-listbox-item-border-color, transparent);
    border-radius: var(--moduix-listbox-item-radius, var(--moduix-radius-sm));
    padding-block: var(
      --moduix-listbox-item-padding-y,
      var(--moduix-popup-item-padding-y, var(--moduix-spacing-1))
    );
    padding-inline: var(
      --moduix-listbox-item-padding-x,
      var(--moduix-popup-item-padding-x-start, var(--moduix-spacing-3))
    );
    background-color: var(--moduix-listbox-item-bg, transparent);
    color: var(
      --moduix-listbox-item-color,
      var(--moduix-listbox-color, var(--moduix-color-foreground))
    );
    font: inherit;
    font-size: var(
      --moduix-listbox-item-font-size,
      var(--moduix-popup-item-font-size, var(--moduix-text-sm))
    );
    line-height: var(
      --moduix-listbox-item-line-height,
      var(--moduix-popup-item-line-height, var(--moduix-line-height-text-sm))
    );
    outline: 0;
    user-select: none;
    cursor: pointer;
    transition:
      background-color var(--moduix-listbox-transition, var(--moduix-transition-default)),
      color var(--moduix-listbox-transition, var(--moduix-transition-default));

    @media (hover: hover) {
      &:not([data-disabled]):hover {
        background-color: var(
          --moduix-listbox-hover-bg,
          var(--moduix-listbox-highlight-bg, var(--moduix-color-accent))
        );
        color: var(
          --moduix-listbox-hover-color,
          var(--moduix-listbox-highlight-color, var(--moduix-color-accent-foreground))
        );
      }
    }

    &[data-highlighted] {
      background-color: var(--moduix-listbox-highlight-bg, var(--moduix-color-accent));
      color: var(--moduix-listbox-highlight-color, var(--moduix-color-accent-foreground));
    }

    &[data-selected] {
      color: var(
        --moduix-listbox-item-selected-color,
        var(--moduix-listbox-item-color, var(--moduix-color-foreground))
      );
    }

    &[data-disabled] {
      pointer-events: none;
      color: var(--moduix-listbox-item-disabled-color, var(--moduix-color-muted-foreground));
      opacity: var(--moduix-listbox-disabled-opacity, var(--moduix-opacity-disabled));
      cursor: default;
    }
  }

  .content[data-orientation='horizontal']:not([data-layout='grid']) .item {
    width: var(--moduix-listbox-horizontal-item-width, 11rem);
    min-width: var(--moduix-listbox-horizontal-item-width, 11rem);
    align-items: flex-start;
  }

  .content[data-layout='grid'] .item {
    width: 100%;
    min-width: 0;
    grid-template-columns: minmax(0, 1fr);
    justify-items: center;
    margin-inline: 0;
    text-align: center;

    &[data-selected] {
      background-color: var(--moduix-listbox-grid-selected-bg, var(--moduix-color-muted));
      color: var(--moduix-listbox-grid-selected-color, var(--moduix-color-foreground));
    }
  }

  .itemText {
    min-width: 0;
    flex: 1;
    overflow: hidden;
    text-overflow: ellipsis;
    white-space: nowrap;
  }

  .itemIndicator {
    display: inline-flex;
    width: var(--moduix-listbox-item-indicator-size, var(--moduix-spacing-4));
    height: var(--moduix-listbox-item-indicator-size, var(--moduix-spacing-4));
    flex-shrink: 0;
    align-items: center;
    justify-content: center;
    color: var(--moduix-listbox-item-indicator-color, currentColor);

    & > svg {
      width: var(--moduix-listbox-item-indicator-icon-size, var(--moduix-spacing-3));
      height: var(--moduix-listbox-item-indicator-icon-size, var(--moduix-spacing-3));
    }

    &[data-state='unchecked'] {
      visibility: hidden;
    }
  }

  .valueText {
    color: var(--moduix-listbox-value-text-color, var(--moduix-color-muted-foreground));
    font-size: var(--moduix-listbox-value-text-font-size, var(--moduix-text-sm));
    line-height: var(--moduix-listbox-value-text-line-height, var(--moduix-line-height-text-sm));
  }

  .itemTextContent {
    display: inline-flex;
    max-width: 100%;
    min-width: 0;
    align-items: center;
    gap: var(--moduix-listbox-item-text-content-gap, var(--moduix-spacing-2));
    vertical-align: top;
  }

  .itemTextIcon {
    display: inline-flex;
    width: var(--moduix-listbox-item-text-icon-size, var(--moduix-spacing-4));
    height: var(--moduix-listbox-item-text-icon-size, var(--moduix-spacing-4));
    flex-shrink: 0;
    align-items: center;
    justify-content: center;
    color: var(--moduix-listbox-item-text-icon-color, currentColor);
  }

  .itemTextLabel {
    min-width: 0;
    overflow: hidden;
    text-overflow: ellipsis;
    white-space: nowrap;
  }
}
